from typing import List


class Solution:
    def balanced_permutation(self, arr: List[int]) -> str:
        n = len(arr)
        if n == 0:
            return ""

        pos = [0] * (n + 1)
        for index, value in enumerate(arr):
            pos[value] = index

        result = []
        min_pos = n           # larger than any valid index
        max_pos = -1
        for k in range(1, n + 1):
            p = pos[k]
            if p < min_pos:
                min_pos = p
            if p > max_pos:
                max_pos = p
            if max_pos - min_pos + 1 == k:
                result.append('1')
            else:
                result.append('0')
        return ''.join(result)


# ---- brute force oracle ----
def brute(arr: List[int]) -> str:
    n = len(arr)
    res = []
    for k in range(1, n + 1):
        ok = False
        for l in range(n):
            s = set()
            valid = True
            for r in range(l, n):
                if arr[r] > k or arr[r] in s:
                    valid = False
                    break
                s.add(arr[r])
                if len(s) == k:
                    ok = True
                    break
            if ok:
                break
        res.append('1' if ok else '0')
    return ''.join(res)


if __name__ == "__main__":
    sol = Solution()
    print(sol.balanced_permutation([1, 3, 2, 4]), "expected 1011")
    print(sol.balanced_permutation([3, 1, 2, 4]), "expected 1111")
    print(sol.balanced_permutation([1]), "expected 1")
    print(sol.balanced_permutation([2, 1]), "expected 11")
    print(sol.balanced_permutation([4, 3, 2, 1]), "expected 1111")
    print(sol.balanced_permutation([2, 4, 1, 3]), "single check")

    import random
    for _ in range(3000):
        n = random.randint(1, 8)
        perm = list(range(1, n + 1))
        random.shuffle(perm)
        if sol.balanced_permutation(perm) != brute(perm):
            print("MISMATCH", perm, sol.balanced_permutation(perm), brute(perm))
            break
    else:
        print("all random tests passed")
